def word_search(board, word):
    rows = len(board)
    cols = len(board[0])

    if not word:
        return True

    def dfs(r, c, k):
        if k == len(word):
            return True

        if not (0 <= r < rows and 0 <= c < cols) or board[r][c] != word[k]:
            return False

        temp = board[r][c]
        board[r][c] = '#' 

        if (dfs(r + 1, c, k + 1) or
                dfs(r - 1, c, k + 1) or
                dfs(r, c + 1, k + 1) or
                dfs(r, c - 1, k + 1)):
            return True

        board[r][c] = temp 
        return False

    for r_start in range(rows):
        for c_start in range(cols):
            if board[r_start][c_start] == word[0]:
                if dfs(r_start, c_start, 0):
                    return True

    return False
